SELECT count(*) FROM keyword, movie_keyword, title, movie_info, info_type, cast_info, role_type, movie_companies WHERE movie_keyword.keyword_id = keyword.id AND movie_keyword.movie_id = title.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_companies.movie_id = title.id;